export const getSiteSearchUrl = (params: SiteSearchParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/search?${stringifiedParams}` : `/api/search`
}

/**
 * @summary Site-wide search
 */
export const siteSearch = async (params: SiteSearchParams, options?: RequestInit): Promise<SearchResults> => {

  return customFetch<SearchResults>(getSiteSearchUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





